import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

import { source } from '@mathjax/src/components/mjs/source.js'

const GENERATED_NOTICE = [
  '// Browser entry (bundler usage recommended).',
  '// Install `@mathjax/src` and let your bundler resolve it from node_modules.',
  '// If you serve ESM directly, map `@mathjax/src` to your hosted MathJax v4 sources.',
  '// For SVG fonts in browsers, import the font class and pass it via `svgFont`.',
  '//',
  '// This file is generated by `node tools/generate-browser-entry.js`.',
]

export const getBrowserTexExtensionNames = () =>
  Object.keys(source)
    .filter((name) => name.startsWith('[tex]/'))
    .map((name) => name.slice(6))
    .filter((name) => name !== 'bussproofs' && name !== 'bboldx')

export const renderBrowserEntry = () => {
  const texExtensionNames = getBrowserTexExtensionNames()
  const imports = texExtensionNames.map(
    (name) => `import '@mathjax/src/components/mjs/input/tex/extensions/${name}/${name}.js'`
  )
  const extensionList = texExtensionNames.map((name) => `  '${name}',`)

  return `${GENERATED_NOTICE.join('\n')}
${imports.join('\n')}

import createMathTexToMathML from './math-tex-to-mathml-core.js'

const TEX_EXTENSION_NAMES = [
${extensionList.join('\n')}
]

const texPackages = ['base', ...TEX_EXTENSION_NAMES]

const mditMathTexToMathML = createMathTexToMathML({ texPackages })

export default mditMathTexToMathML
`
}

export const syncBrowserEntry = ({ check = false } = {}) => {
  const scriptPath = fileURLToPath(import.meta.url)
  const rootDir = path.resolve(path.dirname(scriptPath), '..')
  const targetPath = path.join(rootDir, 'script', 'math-tex-to-mathml.js')
  const nextContent = renderBrowserEntry()
  const currentContent = fs.existsSync(targetPath)
    ? fs.readFileSync(targetPath, 'utf8')
    : ''

  if (currentContent === nextContent) {
    return { changed: false, targetPath }
  }
  if (check) {
    throw new Error(`Browser entry is out of sync: ${targetPath}`)
  }

  fs.writeFileSync(targetPath, nextContent)
  return { changed: true, targetPath }
}

const isMain = process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)

if (isMain) {
  const check = process.argv.includes('--check')
  const { changed, targetPath } = syncBrowserEntry({ check })
  const action = check ? 'Verified' : changed ? 'Updated' : 'Unchanged'
  console.log(`${action}: ${targetPath}`)
}
